/**
 * Nœud 2 : HTTP Fetcher avec rate limiting
 * Récupère le HTML brut de chaque URL.
 * Rate limit : 1 requête / 2 secondes (respectueux du site).
 */
const item = $input.item.json;
const url = item.url;

if (!url) return { json: { ...item, error: 'url_manquante', html: '' } };

// Rate limiting via globalThis (partagé entre exécutions du même nœud)
const g = globalThis;
g.__eitiLastFetch = g.__eitiLastFetch || 0;
const now = Date.now();
const elapsed = now - g.__eitiLastFetch;
const RATE_LIMIT_MS = 2000;

if (elapsed < RATE_LIMIT_MS) {
  await new Promise(r => setTimeout(r, RATE_LIMIT_MS - elapsed));
}
g.__eitiLastFetch = Date.now();

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: {
      'User-Agent': 'Chafafiya-RAG-Crawler/1.0 (MREITI documentation bot; contact: admin@mreiti.mr)',
      'Accept': 'text/html,application/xhtml+xml',
      'Accept-Language': 'fr,en;q=0.9',
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    timeout: 30000,
  });

  const statusCode = resp.statusCode || resp.status || 0;
  if (statusCode >= 400) {
    return { json: { ...item, error: `http_${statusCode}`, html: '' } };
  }

  const html = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return { json: { ...item, html, fetched_at: new Date().toISOString() } };

} catch (err) {
  return { json: { ...item, error: String(err.message || err), html: '' } };
}

/**
 * Nœud 3 : HTML Parser
 * Extrait le texte propre du HTML EITI.
 * - Supprime nav, footer, scripts, cookies, sidebar
 * - Extrait le contenu principal (article, main, .field--body)
 * - Pour requirements_page : découpe par sous-exigence (H3)
 * - Pour standard : retourne le texte complet
 * Produit des items prêts pour le chunker.
 */

// Process ALL items from HTTP Fetch (one per URL)
const allItems = $input.all();
const allResults = [];

for (const inputItem of allItems) {
  const item = inputItem.json;
  if (!item.html || item.error) {
    allResults.push({ json: { ...item, text: '', skip: true } });
    continue;
  }
  const results = processItem(item);
  allResults.push(...results);
}

return allResults;

function processItem(item) {
const html = String(item.html);
const parseMode = item.parse_mode || 'standard';
const baseUrl = item.url || '';
const documentType = item.document_type || 'note_orientation';

// ── Utilitaires HTML ──────────────────────────────────────────────────────────

function stripTags(h) {
  return String(h || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi, ' ')
    .replace(/<aside[\s\S]*?<\/aside>/gi, ' ')
    .replace(/<!--[\s\S]*?-->/g, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/h[1-6]>/gi, '\n\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<td[^>]*>/gi, ' | ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function extractMainContent(h) {
  // Essayer d'extraire le contenu principal dans cet ordre de priorité
  const patterns = [
    /<article[^>]*>([\s\S]*?)<\/article>/i,
    /<main[^>]*>([\s\S]*?)<\/main>/i,
    /class="[^"]*field--body[^"]*"[^>]*>([\s\S]*?)<\/div>/i,
    /class="[^"]*node__content[^"]*"[^>]*>([\s\S]*?)<\/div>/i,
    /class="[^"]*content[^"]*"[^>]*>([\s\S]*?)<\/div>/i,
    /<body[^>]*>([\s\S]*?)<\/body>/i,
  ];
  for (const pat of patterns) {
    const m = h.match(pat);
    if (m && m[1] && m[1].length > 500) return m[1];
  }
  return h;
}

function extractTitle(h) {
  const m = h.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
  if (m) return stripTags(m[1]).trim();
  const t = h.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  if (t) return stripTags(t[1]).replace(/\s*[|\-–].*$/, '').trim();
  return '';
}

function hashDocId(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return 'web_' + (h >>> 0).toString(16);
}

function docIdFromUrl(url) {
  return hashDocId(String(url || '').replace(/^https?:\/\/eiti\.org/, '').replace(/[\/\s]+/g, '_'));
}

function slugFromUrl(url) {
  return String(url || '').replace(/^https?:\/\/eiti\.org\/fr\//, '').replace(/\/$/, '');
}

// ── Mode : page des exigences (découpage par sous-exigence) ───────────────────
function parseRequirementsPage(html, baseItem) {
  const main = extractMainContent(html);
  const pageTitle = extractTitle(html);

  // Trouver tous les blocs H2/H3 avec leur contenu
  // Pattern : chercher les sections <h2> et <h3> et capturer jusqu'au prochain même niveau
  const results = [];
  const documentId = docIdFromUrl(baseItem.url);

  // Extraire toutes les sections délimitées par H2/H3
  const sectionPattern = /<(h[23])[^>]*(?:id="([^"]*)")?[^>]*>([\s\S]*?)<\/h[23]>([\s\S]*?)(?=<h[23]|$)/gi;
  let match;

  while ((match = sectionPattern.exec(main)) !== null) {
    const level = match[1]; // h2 ou h3
    const headingId = match[2] || '';
    const headingHtml = match[3];
    const contentHtml = match[4] || '';

    const headingText = stripTags(headingHtml).trim();
    const contentText = stripTags(contentHtml).trim();

    if (!headingText || contentText.length < 50) continue;

    // Détecter requirement_hint depuis le titre de section
    let reqHint = '';
    const reqMatch = headingText.match(/\b([1-7])[\._]([0-9]{1,2})(?:[\._]([a-z]))?\b/i);
    if (reqMatch) {
      reqHint = reqMatch[3] ? `${reqMatch[1]}.${reqMatch[2]}.${reqMatch[3]}` : `${reqMatch[1]}.${reqMatch[2]}`;
    }
    const chapterMatch = headingText.match(/exigence\s+([1-7])\b/i);
    const chapter = chapterMatch ? chapterMatch[1] : (reqHint ? reqHint.split('.')[0] : '');

    const fullText = headingText + '\n\n' + contentText;

    results.push({
      json: {
        chunk: fullText,
        embedding_text: fullText,
        source: baseItem.url,
        source_path: baseItem.url,
        document_id: documentId + '_' + (headingId || headingText.slice(0, 20).replace(/\s/g, '_')),
        ingest_source: 'url',
        chunk_index: results.length,
        metadata: {
          source: baseItem.url,
          filename: slugFromUrl(baseItem.url),
          source_path: baseItem.url,
          title: headingText,
          document_id: documentId,
          type: 'html',
          content_type: 'text/html',
          chunk_index: results.length,
          chunk_size_target: 720,
          chunk_overlap: 120,
          ingest_profile: 'web_crawler_eiti_v1',
          document_type: baseItem.document_type || 'norme_itie',
          section_path: headingText,
          requirement_hint: reqHint || undefined,
          itie_chapter: chapter || undefined,
          chunk_type: 'narrative_section',
          has_table: false,
          has_example: false,
          page_title: pageTitle,
          scraped_at: baseItem.fetched_at,
          heading_level: level,
        },
      }
    });
  }

  if (!results.length) {
    // Fallback : tout le texte d'un coup
    const fullText = stripTags(main);
    if (fullText.length > 100) {
      results.push({
        json: {
          chunk: fullText,
          embedding_text: fullText,
          source: baseItem.url,
          source_path: baseItem.url,
          document_id: documentId,
          ingest_source: 'url',
          chunk_index: 0,
          metadata: {
            source: baseItem.url,
            filename: slugFromUrl(baseItem.url),
            source_path: baseItem.url,
            title: pageTitle,
            document_id: documentId,
            type: 'html',
            content_type: 'text/html',
            chunk_index: 0,
            ingest_profile: 'web_crawler_eiti_v1',
            document_type: baseItem.document_type || 'norme_itie',
            chunk_type: 'narrative_section',
            scraped_at: baseItem.fetched_at,
          },
        }
      });
    }
  }

  return results;
}

// ── Mode standard : texte complet → chunker ───────────────────────────────────
function parseStandardPage(html, baseItem) {
  const main = extractMainContent(html);
  const pageTitle = item.title || extractTitle(html);
  const text = stripTags(main);

  if (text.length < 100) {
    return [{ json: { ...baseItem, text: '', skip: true } }];
  }

  const documentId = docIdFromUrl(baseItem.url);

  // Détecter requirement_hint dans le texte
  let reqHint = baseItem.requirement_hint || '';
  if (!reqHint) {
    const m = text.match(/Exigence\s+([1-7])[\._]([0-9]{1,2})/i);
    if (m) reqHint = m[1] + '.' + m[2];
  }
  const chapter = reqHint ? reqHint.split('.')[0] : '';

  return [{
    json: {
      // Champs attendus par le chunker hybride existant
      text,
      data: text,
      path: baseItem.url,
      filePath: baseItem.url,
      fileName: slugFromUrl(baseItem.url) + '.html',
      name: slugFromUrl(baseItem.url) + '.html',
      ingest_source: 'url',
      content_type: 'text/html',
      source_title: pageTitle,
      // Metadata pré-remplie pour guider le chunker
      _meta_override: {
        document_type: baseItem.document_type,
        requirement_hint: reqHint || undefined,
        itie_chapter: chapter || undefined,
        scraped_at: baseItem.fetched_at,
        page_url: baseItem.url,
      },
    }
  }];
}

// ── Dispatch ──────────────────────────────────────────────────────────────────
if (parseMode === 'requirements_page') {
  return parseRequirementsPage(html, item);
}
return parseStandardPage(html, item);
} // end processItem

/**
 * Nœud 4 : Web Chunker
 * Adapte le chunker PDF existant pour le contenu HTML scrappé.
 * - Si l'item vient du parseRequirementsPage (a déjà chunk + metadata) → pass-through
 * - Si l'item vient du parseStandardPage (a text brut) → découpage hybride
 */

function envInt(name, def) {
  try {
    if (typeof process === 'undefined') return def;
    const v = (process.env[name] || '').trim();
    if (!v) return def;
    const n = parseInt(v, 10);
    return Number.isFinite(n) && n > 0 ? n : def;
  } catch (_) { return def; }
}

const CHUNK_TARGET = envInt('INGEST_CHUNK_CHARS', 720);
const OVERLAP = envInt('INGEST_OVERLAP_CHARS', 120);
const CHUNK_HARD_MAX = envInt('INGEST_CHUNK_MAX', 2200);

const items = $input.all();
const out = [];

function hashDocId(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return 'web_' + (h >>> 0).toString(16);
}

function buildEmbeddingPrefix(meta) {
  const parts = [];
  if (meta.document_type) parts.push(meta.document_type.replace(/_/g, ' '));
  if (meta.itie_chapter && !meta.requirement_hint) parts.push('ITIE chapitre exigence ' + meta.itie_chapter);
  if (meta.requirement_hint) parts.push('ITIE exigence ' + meta.requirement_hint);
  if (meta.section_path) parts.push(meta.section_path);
  if (meta.title && !meta.section_path) parts.push(meta.title);
  if (!parts.length) return '';
  return '[' + parts.join(' | ') + ']\n\n';
}

function chunkText(text, target, overlap, hardMax) {
  const chunks = [];
  const paragraphs = text.split(/\n{2,}/).map(p => p.trim()).filter(Boolean);
  let buffer = [];
  let bufLen = 0;

  function flush() {
    if (!buffer.length) return;
    const combined = buffer.join('\n\n');
    buffer = [];
    bufLen = 0;
    if (combined.length <= target) {
      chunks.push(combined);
      return;
    }
    // Découper le bloc trop long
    let start = 0;
    while (start < combined.length) {
      let end = Math.min(start + hardMax, combined.length);
      if (end - start > target && end < combined.length) {
        end = Math.min(start + target, combined.length);
        const sp = combined.lastIndexOf('. ', end);
        if (sp > start + Math.floor(target * 0.45)) end = sp + 2;
      }
      const piece = combined.slice(start, end).trim();
      if (piece) chunks.push(piece);
      if (end >= combined.length) break;
      start = Math.max(start + 1, end - overlap);
    }
  }

  for (const para of paragraphs) {
    if (bufLen + para.length + 2 > target && bufLen > 0) flush();
    buffer.push(para);
    bufLen = buffer.join('\n\n').length;
  }
  flush();
  return chunks;
}

for (const item of items) {
  const j = item.json || {};

  if (j.skip) continue;

  // ── Cas 1 : item déjà chunké (requirements_page) → ajouter embedding_text ──
  if (j.chunk && j.metadata) {
    const meta = j.metadata;
    const embedPrefix = buildEmbeddingPrefix(meta);
    const embedding_text = embedPrefix + j.chunk;
    out.push({
      json: {
        ...j,
        embedding_text,
      }
    });
    continue;
  }

  // ── Cas 2 : texte brut à découper (standard pages) ───────────────────────
  const rawText = j.text || j.data || '';
  if (!rawText || rawText.length < 50) continue;

  const url = j.path || j.filePath || j.source || '';
  const fileName = j.fileName || j.name || 'page.html';
  const title = j.source_title || j._meta_override?.page_url || fileName;
  const documentId = hashDocId(url || fileName);
  const overrides = j._meta_override || {};

  const chunks = chunkText(rawText, CHUNK_TARGET, OVERLAP, CHUNK_HARD_MAX);

  chunks.forEach((chunk, idx) => {
    // Détecter requirement_hint dans le chunk si pas déjà connu
    let reqHint = overrides.requirement_hint || '';
    if (!reqHint) {
      const m = chunk.match(/Exigence\s+([1-7])[\._]([0-9]{1,2})/i);
      if (m) reqHint = m[1] + '.' + m[2];
    }
    const chapter = reqHint ? reqHint.split('.')[0] : (overrides.itie_chapter || '');

    const metadata = {
      source: url,
      filename: fileName,
      source_path: url,
      title,
      document_id: documentId,
      type: 'html',
      content_type: 'text/html',
      chunk_index: idx,
      chunk_size_target: CHUNK_TARGET,
      chunk_overlap: OVERLAP,
      ingest_profile: 'web_crawler_eiti_v1',
      document_type: overrides.document_type || 'note_orientation',
      requirement_hint: reqHint || undefined,
      itie_chapter: chapter || undefined,
      chunk_type: 'narrative_section',
      has_table: false,
      has_example: false,
      scraped_at: overrides.scraped_at,
      page_url: url,
    };

    const embedPrefix = buildEmbeddingPrefix(metadata);
    const embedding_text = embedPrefix + chunk;

    out.push({
      json: {
        chunk,
        embedding_text,
        chunk_index: idx,
        source: fileName,
        source_path: url,
        document_id: documentId,
        metadata,
      }
    });
  });
}

return out;

/* Upsert dense + BM25 — utilise embedding_text (préfixe contextuel) pour vecteur + sparse ;
   payload.content = chunk affiché tel quel pour le LLM. */
const httpRequest = this.helpers.httpRequest.bind(this);

const COLLECTION = 'documents';
const OLLAMA_MODEL = 'nomic-embed-text:latest';
const BM25_TEXT_MAX = 32000;
const EMB_BATCH = 32;
const UPSERT_BATCH = 32;
const EMB_PARALLEL = 8;

function envStr(name) {
  try {
    if (typeof process === 'undefined') return '';
    const pe = process.env;
    if (!pe || typeof pe[name] !== 'string') return '';
    return pe[name];
  } catch (_) {
    return '';
  }
}

function uuid4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    var r = (Math.random() * 16) | 0;
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });
}

async function qdrantReq(method, url, headers, bodyObj) {
  const reqOpts = {
    method,
    url,
    headers,
    json: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  };
  if (bodyObj !== undefined) reqOpts.body = bodyObj;
  const resp = await httpRequest(reqOpts);
  const code = resp.statusCode ?? resp.status ?? 0;
  const body = resp.body ?? resp.data ?? resp;
  if (code >= 400) {
    const errTxt =
      typeof body === 'string'
        ? body
        : body?.status?.error || JSON.stringify(body);
    return { ok: false, code, error: errTxt, raw: body };
  }
  return { ok: true, code, data: body };
}

async function embedTexts(ollamaBase, texts) {
  try {
    const res = await httpRequest({
      method: 'POST',
      url: ollamaBase + '/api/embed',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: OLLAMA_MODEL, input: texts }),
      json: true,
    });
    const embs = res && res.embeddings;
    if (Array.isArray(embs) && embs.length === texts.length) {
      return embs;
    }
  } catch (_) {}
  const out = new Array(texts.length);
  for (let i = 0; i < texts.length; i += EMB_PARALLEL) {
    const slice = texts.slice(i, i + EMB_PARALLEL);
    const baseIdx = i;
    await Promise.all(
      slice.map((t, k) =>
        httpRequest({
          method: 'POST',
          url: ollamaBase + '/api/embeddings',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ model: OLLAMA_MODEL, prompt: t }),
          json: true,
        }).then((r) => {
          out[baseIdx + k] = r.embedding;
        }),
      ),
    );
  }
  return out;
}

let baseUrl = '';
let apiKey = '';
if (typeof this.getCredentials === 'function') {
  try {
    const q = await this.getCredentials('qdrantApi');
    baseUrl = String(q.url || '').replace(/\/$/, '');
    apiKey = q.apiKey || q.api_key || '';
  } catch (_) {}
}
if (!baseUrl)
  baseUrl = String(envStr('QDRANT_URL') || 'http://127.0.0.1:6333').replace(
    /\/$/,
    '',
  );

let ollamaBase = '';
if (typeof this.getCredentials === 'function') {
  try {
    const o = await this.getCredentials('ollamaApi');
    ollamaBase = String(o.baseUrl || o.host || o.url || '').replace(/\/$/, '');
  } catch (_) {}
}
if (!ollamaBase)
  ollamaBase = String(envStr('OLLAMA_URL') || 'http://127.0.0.1:11434').replace(
    /\/$/,
    '',
  );

const qH = { 'Content-Type': 'application/json' };
if (apiKey) qH['api-key'] = apiKey;

let qdrantVersion = '';
try {
  const ri = await httpRequest({
    method: 'GET',
    url: baseUrl,
    headers: qH,
    json: true,
  });
  if (ri && ri.version) qdrantVersion = ri.version;
} catch (_) {}

const colRes = await qdrantReq(
  'GET',
  baseUrl + '/collections/' + encodeURIComponent(COLLECTION),
  qH,
  undefined,
);
if (!colRes.ok) {
  throw new Error(
    'Collection "' +
      COLLECTION +
      '" introuvable (' +
      colRes.code +
      '). Lancez Setup. ' +
      String(colRes.error).slice(0, 500),
  );
}
const colData =
  colRes.data && colRes.data.result !== undefined
    ? colRes.data.result
    : colRes.data;
const colParams =
  (colData && colData.config && colData.config.params) || colData.params || {};
const vectors = colParams.vectors || {};
let expectedDim = null;
if (vectors.dense && vectors.dense.size) expectedDim = vectors.dense.size;
else if (typeof vectors.size === 'number') expectedDim = vectors.size;
const sparseKeys = Object.keys(colParams.sparse_vectors || {});
if (sparseKeys.indexOf('text-bm25') < 0) {
  throw new Error(
    'Sparse "text-bm25" absent. Recréez la collection (DROP_COLLECTION_FIRST=true).',
  );
}

const upsertUrl =
  baseUrl +
  '/collections/' +
  encodeURIComponent(COLLECTION) +
  '/points?wait=false';
const rows = $input.all();

const chunks = [];
for (let i = 0; i < rows.length; i++) {
  const json = rows[i].json || {};
  const raw = json.chunk;
  if (!raw || !String(raw).trim()) continue;
  const embedSrc = json.embedding_text || json.chunk;
  const safe = String(raw).replace(/\0/g, '');
  const safeEmbed = String(embedSrc).replace(/\0/g, '');
  const bm25Src =
    safeEmbed.length > BM25_TEXT_MAX
      ? safeEmbed.slice(0, BM25_TEXT_MAX)
      : safeEmbed;
  const meta = json.metadata || { source: json.source, type: 'pdf' };
  chunks.push({
    idx: i,
    text: safe,
    embedText: safeEmbed,
    bm25: bm25Src,
    meta,
    source: json.source,
    chunk_index: json.chunk_index,
  });
}

const embeddings = [];
for (let b = 0; b < chunks.length; b += EMB_BATCH) {
  const slice = chunks.slice(b, b + EMB_BATCH);
  const vecs = await embedTexts(
    ollamaBase,
    slice.map(function (c) {
      return c.embedText;
    }),
  );
  for (let k = 0; k < vecs.length; k++) {
    var emb = vecs[k];
    if (!Array.isArray(emb) || !emb.length) {
      throw new Error('[chunk ' + slice[k].idx + '] Ollama: embedding vide');
    }
    if (expectedDim != null && emb.length !== expectedDim) {
      throw new Error(
        '[chunk ' +
          slice[k].idx +
          '] Dimension=' +
          emb.length +
          ' vs collection=' +
          expectedDim,
      );
    }
    embeddings.push(emb);
  }
}

const results = [];
for (let b = 0; b < chunks.length; b += UPSERT_BATCH) {
  var batchChunks = chunks.slice(b, b + UPSERT_BATCH);
  var batchEmbs = embeddings.slice(b, b + UPSERT_BATCH);
  var points = batchChunks.map(function (c, k) {
    const m = c.meta || {};
    return {
      id: uuid4(),
      vector: {
        dense: batchEmbs[k],
        'text-bm25': {
          text: c.bm25,
          model: 'qdrant/bm25',
          options: { language: 'french' },
        },
      },
      payload: {
        content: c.text,
        page_content: c.text,
        document_id: m.document_id,
        source: c.source,
        chunk_index: c.chunk_index,
        metadata: m,
        document_type: m.document_type,
        chunk_type: m.chunk_type,
        section_path: m.section_path,
        requirement_hint: m.requirement_hint,
      },
    };
  });

  var res = await qdrantReq('PUT', upsertUrl, qH, { points: points });
  if (!res.ok) {
    throw new Error(
      '[lot interne ' +
        Math.floor(b / UPSERT_BATCH) +
        '] Qdrant ' +
        (qdrantVersion || '?') +
        ' HTTP ' +
        res.code +
        ' : ' +
        String(res.error).slice(0, 2000),
    );
  }

  for (var k = 0; k < batchChunks.length; k++) {
    results.push({
      json: {
        upserted: true,
        pointId: points[k].id,
        source: batchChunks[k].source,
        chunk_index: batchChunks[k].chunk_index,
      },
    });
  }
}

return results;
